import { connectDB } from "@/lib/db"
import ExecutionWorkspace from "@/models/ExecutionWorkspace"
import { NextRequest, NextResponse } from "next/server"

// PUT - Update executionCosts in workspace
export async function PUT(req: NextRequest) {
  try {
    await connectDB()
    const body = await req.json()
    const { workspaceId, executionCosts } = body

    if (!workspaceId || !executionCosts) {
      return NextResponse.json(
        { message: "Workspace ID and executionCosts are required" },
        { status: 400 }
      )
    }

    const workspace = await ExecutionWorkspace.findByIdAndUpdate(
      workspaceId,
      { executionCosts },
      { new: true, runValidators: true }
    )

    if (!workspace) {
      return NextResponse.json(
        { message: "Workspace not found" },
        { status: 404 }
      )
    }

    return NextResponse.json(
      { success: true, data: workspace },
      { status: 200 }
    )
  } catch (error) {
    console.error("Update execution costs error:", error)
    return NextResponse.json(
      { message: "Failed to update execution costs" },
      { status: 500 }
    )
  }
}